SELECT n.id, n.title, n.content, n.type, n.status, n.pinned, u.full_name AS posted_by_name, TO_CHAR(n.published_at, 'YYYY-MM-DD HH24:MI:SS') AS published_at, TO_CHAR(n.created_at, 'YYYY-MM-DD HH24:MI:SS') AS created_at FROM notices n LEFT JOIN users u ON u.id = n.posted_by WHERE n.delete_flg = 0
AND n.type = #{type}
AND n.status = #{status}
ORDER BY n.pinned DESC, n.created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM notices n
WHERE n.delete_flg = 0

  AND n.type = #{type}


  AND n.status = #{status}
